def vacuum_agent(location, status):
    if status == "dirty":
        return "suck"
    elif location == "A":
        return "move_right"
    else:
        return "move_left"

percepts = [("B", "dirty"), ("B", "clean"), ("A", "clean")]
for loc, stat in percepts:
    print(vacuum_agent(loc, stat))

